from __future__ import annotations

from pathlib import Path
import json
import pandas as pd

from .core import POSITION_ORDER, bool_series

TEAM_SHORT = {
    "Wakefield Trinity": "Wakefield", "Castleford": "Castleford", "Catalans": "Catalans",
    "Huddersfield": "Huddersfield", "Hull FC": "Hull FC", "Hull KR": "Hull KR",
    "Leeds": "Leeds", "Leigh": "Leigh", "Salford": "Salford", "St Helens": "St Helens",
    "Warrington": "Warrington", "Wigan": "Wigan", "Bradford": "Bradford",
    "Toulouse": "Toulouse", "York": "York",
}


def short(team):
    return TEAM_SHORT.get(str(team), str(team))


def _safe_csv(path: Path) -> pd.DataFrame:
    if not path.exists() or path.stat().st_size == 0:
        return pd.DataFrame()
    try:
        return pd.read_csv(path)
    except pd.errors.EmptyDataError:
        return pd.DataFrame()


def _records(df: pd.DataFrame, cols: list[str]) -> list[dict]:
    if df.empty:
        return []
    for col in cols:
        if col not in df.columns:
            df[col] = None
    clean = df[cols].astype(object).where(pd.notna(df[cols]), None)
    return clean.to_dict("records")


def refresh_outputs(root: Path | str):
    root = Path(root)
    data = root / "data"
    exports = root / "exports"
    exports.mkdir(exist_ok=True)

    matches = _safe_csv(data / "matches.csv")
    events = _safe_csv(data / "try_events.csv")
    lineups = _safe_csv(data / "lineups.csv")
    fixtures = _safe_csv(data / "fixtures.csv")
    teamlists = _safe_csv(data / "teamlists.csv")
    player_stats = _safe_csv(data / "player_stats.csv")
    try:
        status = json.loads((data / "update_status.json").read_text(encoding="utf-8"))
    except Exception:
        status = {}

    if not matches.empty:
        matches["is_final"] = bool_series(matches["is_final"])
    if not events.empty:
        events["is_final"] = bool_series(events["is_final"])
    if not lineups.empty and "is_starting" in lineups:
        lineups["is_starting"] = bool_series(lineups["is_starting"])
    if not teamlists.empty and "is_starting" in teamlists:
        teamlists["is_starting"] = bool_series(teamlists["is_starting"])

    # Useful exports for manual checking and external analysis.
    if not matches.empty:
        matches.to_csv(exports / "all_matches.csv", index=False)
    if not events.empty:
        events.to_csv(exports / "all_try_events.csv", index=False)
    if not fixtures.empty:
        fixtures.to_csv(exports / "fixtures_and_status.csv", index=False)
    if not teamlists.empty:
        teamlists.to_csv(exports / "weekly_teamlists.csv", index=False)
    if not player_stats.empty:
        player_stats.to_csv(exports / "official_player_stats.csv", index=False)

    teams = set()
    for frame, cols in ((matches, ["home_team", "away_team"]), (fixtures, ["home_team", "away_team"]), (teamlists, ["team", "opposition_team"])):
        if not frame.empty:
            for col in cols:
                if col in frame:
                    teams.update(frame[col].dropna().astype(str))

    review_path = data / "review_queue.csv"
    review_count = len(_safe_csv(review_path))
    manifest = {
        "2025_matches": int((matches.get("season", pd.Series(dtype=int)).astype(str) == "2025").sum()) if not matches.empty else 0,
        "2026_matches": int((matches.get("season", pd.Series(dtype=int)).astype(str) == "2026").sum()) if not matches.empty else 0,
        "2026_tries": int(pd.to_numeric(events.loc[events.get("season", pd.Series(dtype=int)).astype(str) == "2026", "tries"], errors="coerce").fillna(0).sum()) if not events.empty else 0,
        "2026_position_matches": int(lineups.loc[lineups.get("season", pd.Series(dtype=int)).astype(str) == "2026", "match_id"].nunique()) if not lineups.empty else 0,
        "2026_lineup_rows": int((lineups.get("season", pd.Series(dtype=int)).astype(str) == "2026").sum()) if not lineups.empty else 0,
        "fixtures": len(fixtures),
        "teamlist_rows": len(teamlists),
        "player_stat_rows": len(player_stats),
        "teams": len(teams),
        "review_queue_rows": review_count,
        "positions": POSITION_ORDER,
    }
    (root / "data_manifest.json").write_text(json.dumps(manifest, indent=2) + "\n", encoding="utf-8")

    match_cols = ["match_id", "season", "round_label", "round_number", "date", "home_team", "home_team_score", "away_team", "away_team_score", "is_final", "venue", "source_url"]
    event_cols = ["match_id", "season", "round_label", "round_number", "date", "is_final", "team", "opposition_team", "full_name", "player_key", "display_position", "tries", "position_method", "source_url"]
    lineup_cols = ["match_id", "season", "round_label", "round_number", "date", "team", "opposition_team", "full_name", "player_key", "jersey_number", "raw_position", "display_position", "is_starting", "source_url"]
    fixture_cols = ["match_id", "season", "round_label", "round_number", "date", "kickoff", "status", "home_team", "away_team", "venue", "source_url", "last_checked_utc"]
    teamlist_cols = ["match_id", "season", "round_label", "round_number", "date", "kickoff", "team", "opposition_team", "full_name", "player_key", "jersey_number", "raw_position", "display_position", "is_starting", "source_url", "last_checked_utc"]
    player_cols = ["season", "rank", "player", "player_key", "team", "team_method", "games", "tries", "try_assists", "tackles", "missed_tackles", "minutes", "tackle_busts", "attacking_kicks", "carries", "metres", "average_gain", "clean_breaks", "drop_outs", "drop_goals", "errors", "forty_twenty", "goals", "missed_goals", "offloads", "penalties", "red_cards", "yellow_cards", "source_url", "updated_utc"]

    replacements = {
        "__MATCHES__": json.dumps(_records(matches, match_cols), ensure_ascii=False, separators=(",", ":"), default=str),
        "__EVENTS__": json.dumps(_records(events, event_cols), ensure_ascii=False, separators=(",", ":"), default=str),
        "__LINEUPS__": json.dumps(_records(lineups, lineup_cols), ensure_ascii=False, separators=(",", ":"), default=str),
        "__FIXTURES__": json.dumps(_records(fixtures, fixture_cols), ensure_ascii=False, separators=(",", ":"), default=str),
        "__TEAMLISTS__": json.dumps(_records(teamlists, teamlist_cols), ensure_ascii=False, separators=(",", ":"), default=str),
        "__PLAYER_STATS__": json.dumps(_records(player_stats, player_cols), ensure_ascii=False, separators=(",", ":"), default=str),
        "__STATUS__": json.dumps(status, ensure_ascii=False, separators=(",", ":"), default=str),
        "__MANIFEST__": json.dumps(manifest, ensure_ascii=False, separators=(",", ":")),
        "__POSITIONS__": json.dumps(POSITION_ORDER),
    }
    html = HTML_TEMPLATE
    for token, value in replacements.items():
        html = html.replace(token, value)
    (root / "index.html").write_text(html, encoding="utf-8")
    return manifest


